export interface Stock {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
  volume: number;
  sector: string;
}

export interface Candle {
  time: string; // ISO String or readable time
  open: number;
  high: number;
  low: number;
  close: number;
  volume: number;
  isPrediction?: boolean;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model' | 'system';
  text: string;
  timestamp: Date;
  isTyping?: boolean;
}

export enum TimeFrame {
  D1 = '1D',
  W1 = '1W',
  M1 = '1M',
  M3 = '3M',
  Y1 = '1Y',
}

export interface PredictionResult {
  confidence: number;
  trend: 'UP' | 'DOWN' | 'NEUTRAL';
  riskLevel: 'LOW' | 'MEDIUM' | 'HIGH';
  targetPrice: number;
  reasoning: string;
}

import { Candle, Stock, TimeFrame } from '../types';

// Mock list of stocks
export const WATCHLIST: Stock[] = [
  { symbol: 'AAPL', name: 'Apple Inc.', price: 175.43, change: 1.25, changePercent: 0.72, volume: 45000000, sector: 'Technology' },
  { symbol: 'NVDA', name: 'NVIDIA Corp.', price: 890.12, change: 15.30, changePercent: 1.75, volume: 32000000, sector: 'Technology' },
