// Helper to generate random candles
export const generateHistory = (symbol: string, timeframe: TimeFrame): Candle[] => {
  const data: Candle[] = [];
  let points = 100;
  let intervalMinutes = 60; // Default 1H

  switch (timeframe) {
    case TimeFrame.D1: points = 48; intervalMinutes = 30; break; // Every 30 mins
    case TimeFrame.W1: points = 84; intervalMinutes = 120; break;
    case TimeFrame.M1: points = 30; intervalMinutes = 1440; break; // Daily
    case TimeFrame.M3: points = 90; intervalMinutes = 1440; break;
    case TimeFrame.Y1: points = 52; intervalMinutes = 10080; break; // Weekly
  }

  // Seed price based on symbol
  let currentPrice = WATCHLIST.find(s => s.symbol === symbol)?.price || 100;
  // Start date back in time
  let time = new Date();
  time.setMinutes(time.getMinutes() - (points * intervalMinutes));

  for (let i = 0; i < points; i++) {
    const volatility = currentPrice * 0.02; // 2% volatility
    const change = (Math.random() - 0.5) * volatility;

    const open = currentPrice;
    const close = currentPrice + change;
    const high = Math.max(open, close) + Math.random() * (volatility * 0.5);
    const low = Math.min(open, close) - Math.random() * (volatility * 0.5);
    const volume = Math.floor(Math.random() * 1000000) + 500000;

    data.push({
      time: time.toISOString(),
      open,
      high,
      low,
      close,
      volume,
      isPrediction: false
    });

    currentPrice = close;
    time = new Date(time.getTime() + intervalMinutes * 60000);
  }

  return data;
};

// Simulate live updates
type Listener = (stock: Stock) => void;
const listeners: Map<string, Listener[]> = new Map();

export const subscribeToTicker = (symbol: string, callback: Listener) => {
  if (!listeners.has(symbol)) {
    listeners.set(symbol, []);
  }
  listeners.get(symbol)?.push(callback);

  // Start simulation if not already running globally (mock implementation simplified)
  const interval = setInterval(() => {
    const stock = WATCHLIST.find(s => s.symbol === symbol);
    if (stock) {
      // Random walk
      const delta = (Math.random() - 0.45) * (stock.price * 0.002);
      stock.price += delta;
      stock.change += delta;
      stock.changePercent = (stock.change / (stock.price - stock.change)) * 100;

      callback({ ...stock });
    }
  }, 3000);

  return () => {
    const list = listeners.get(symbol);
    if (list) {
      const index = list.indexOf(callback);
      if (index > -1) list.splice(index, 1);
    }
    clearInterval(interval);
  };
};

import { GoogleGenAI, Type } from "@google/genai";
import { Candle, Stock } from "../types";

const API_KEY = process.env.API_KEY || ''; // Ensure this is set
const ai = new GoogleGenAI({ apiKey: API_KEY });

const SYSTEM_INSTRUCTION = `
You are Nova, an elite AI Financial Analyst for a high-frequency trading platform. 
Your goal is to provide concise, data-driven insights on stock market trends.
You are analytical, objective, and professional, but accessible.

IMPORTANT RULES:
1. Always include a disclaimer: "Not financial advice."
2. Analyze technical indicators (RSI, MACD, Moving Averages) if data is provided.
3. Be concise. Use markdown for formatting.
4. If asked to predict, assess trends but emphasize uncertainty.
`;

export const getGeminiChatResponse = async (
  message: string, 
  currentStock: Stock, 
  contextData?: string
) => {
  try {
    const model = 'gemini-3-flash-preview';

    let fullPrompt = `User Query: "${message}"\n\n`;
    fullPrompt += `Current Focus Stock: ${currentStock.symbol} (${currentStock.name}) Price: $${currentStock.price.toFixed(2)}\n`;

    if (contextData) {
      fullPrompt += `Recent Market Data Context: ${contextData}\n`;
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: fullPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm currently unable to connect to the market analysis network. Please try again later.";
  }
};

export const generateAIPrediction = async (symbol: string, history: Candle[]) => {
  try {
    const model = 'gemini-3-flash-preview'; // Using Flash for speed in this demo

    // Simplify history to reduce token count for demo
    const simplifiedHistory = history.slice(-20).map(c => 
      `${c.time.split('T')[0]}: Close $${c.close.toFixed(2)}, Vol ${c.volume}`
    ).join('\n');

    const prompt = `
      Analyze the following 20-day price history for ${symbol}:
      ${simplifiedHistory}

      Perform a technical analysis simulation.
      Return a JSON object with the following structure:
      {
        "trend": "UP" | "DOWN" | "NEUTRAL",
        "confidence": number (0-100),
        "riskLevel": "LOW" | "MEDIUM" | "HIGH",
        "targetPrice": number (predicted price in 5 periods),
        "reasoning": "Short string explaining why (max 15 words)",
        "predictedPath": [number, number, number, number, number] (next 5 closing prices)
      }
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            trend: { type: Type.STRING, enum: ["UP", "DOWN", "NEUTRAL"] },
            confidence: { type: Type.NUMBER },
            riskLevel: { type: Type.STRING, enum: ["LOW", "MEDIUM", "HIGH"] },
            targetPrice: { type: Type.NUMBER },
            reasoning: { type: Type.STRING },
            predictedPath: { 
              type: Type.ARRAY, 
              items: { type: Type.NUMBER } 
            }
          }
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Prediction Error:", error);
    return null;
  }
};

