import React from 'react';
import {
  ResponsiveContainer,
  ComposedChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Bar,
  ReferenceLine,
  Line
} from 'recharts';
import { Candle } from '../../types';

interface MarketChartProps {
  data: Candle[];
  symbol: string;
}

const MarketChart: React.FC<MarketChartProps> = ({ data, symbol }) => {
  const isPositive = data.length > 0 && data[data.length - 1].close >= data[0].close;
  const strokeColor = isPositive ? '#10b981' : '#ef4444'; // Emerald or Red
  const fillColor = isPositive ? 'url(#colorUp)' : 'url(#colorDown)';

  // Format date for X Axis
  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const d = payload[0].payload as Candle;
      return (
        <div className="bg-slate-900 border border-slate-700 p-3 rounded shadow-xl backdrop-blur-md bg-opacity-90">
          <p className="text-slate-400 text-xs mb-1">{new Date(label).toLocaleString()}</p>
          <p className="font-mono text-sm text-white">Price: <span className="font-bold">${d.close.toFixed(2)}</span></p>
          {d.isPrediction && (
             <p className="text-xs text-indigo-400 font-semibold mt-1">✨ AI Prediction</p>
          )}
          {!d.isPrediction && (
            <>
              <p className="font-mono text-xs text-slate-400">Open: ${d.open.toFixed(2)}</p>
              <p className="font-mono text-xs text-slate-400">High: ${d.high.toFixed(2)}</p>
              <p className="font-mono text-xs text-slate-400">Low: ${d.low.toFixed(2)}</p>
            </>
          )}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="w-full h-full min-h-[400px]">
      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
          <defs>
            <linearGradient id="colorUp" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="colorDown" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
          <XAxis 
            dataKey="time" 
            tickFormatter={formatDate} 
            stroke="#64748b" 
            tick={{ fontSize: 12 }} 
            minTickGap={30}
          />
          <YAxis 
            domain={['auto', 'auto']} 
            orientation="right" 
            stroke="#64748b" 
            tick={{ fontSize: 12 }} 
            tickFormatter={(val) => `$${val.toFixed(0)}`}
          />
          <Tooltip content={<CustomTooltip />} />

          {/* Main Price Line/Area */}
          <Area 
            type="monotone" 
            dataKey="close" 
            stroke={strokeColor} 
            fill={fillColor} 
            strokeWidth={2}
            connectNulls
          />

          {/* Volume Bars (Simulated at bottom) */}
           {/* Note: In a composed chart, bars share the same Y axis unless specified. 
               For simplicity in this generated code, we skip volume bars to keep the Y-axis clean for price.
           */}

          {/* Prediction Line (Dashed) */}
          <Line 
            type="monotone"
            dataKey="close"
            stroke="#6366f1"
            strokeWidth={2}
            strokeDasharray="5 5"
            dot={false}
            data={data.filter(d => d.isPrediction)} // This won't work directly in Recharts simply.
            // Alternate strategy: Data includes both. We use a separate Line for predictions if we had separate keys.
            // But since we use same key 'close', we rely on the Area for history.
            // Let's add a ReferenceLine for the start of prediction.
          />

          {data.find(d => d.isPrediction) && (
             <ReferenceLine x={data.find(d => d.isPrediction)?.time} stroke="#6366f1" strokeDasharray="3 3" label={{ position: 'top', value: 'PREDICTION', fill: '#818cf8', fontSize: 10 }} />
          )}

        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
};

export default MarketChart;

import React from 'react';
import { Stock, TimeFrame } from '../../types';
import { ArrowUp, ArrowDown, Clock, Activity, Zap } from 'lucide-react';

interface StockHeaderProps {
  stock: Stock;
  timeframe: TimeFrame;
  setTimeframe: (tf: TimeFrame) => void;
  onRunPrediction: () => void;
  isPredicting: boolean;
}

const StockHeader: React.FC<StockHeaderProps> = ({ 
  stock, 
  timeframe, 
  setTimeframe, 
  onRunPrediction, 
  isPredicting 
}) => {
  const isPositive = stock.change >= 0;

  return (
    <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
      <div>
        <div className="flex items-center gap-3">
          <h1 className="text-3xl font-bold text-white tracking-tight">{stock.symbol}</h1>
          <span className="text-slate-400 text-sm font-medium bg-slate-800 px-2 py-1 rounded">{stock.name}</span>
          <span className="text-slate-500 text-xs px-2 py-1 border border-slate-700 rounded-full">{stock.sector}</span>
        </div>
        <div className="flex items-center gap-4 mt-1">
          <span className="text-4xl font-mono font-medium text-white">${stock.price.toFixed(2)}</span>
          <div className={`flex items-center px-2 py-1 rounded text-sm font-bold ${isPositive ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
            {isPositive ? <ArrowUp size={16} /> : <ArrowDown size={16} />}
            {Math.abs(stock.change).toFixed(2)} ({Math.abs(stock.changePercent).toFixed(2)}%)
          </div>
        </div>
      </div>

      <div className="flex flex-col items-end gap-3">
        <div className="flex bg-slate-800 p-1 rounded-lg">
          {Object.values(TimeFrame).map((tf) => (
            <button
              key={tf}
              onClick={() => setTimeframe(tf)}
              className={`px-3 py-1 text-xs font-semibold rounded-md transition-all ${
                timeframe === tf 
                  ? 'bg-slate-700 text-white shadow' 
                  : 'text-slate-400 hover:text-white'
              }`}
            >
              {tf}
            </button>
          ))}
        </div>
        <div className="flex gap-2">
            <button 
                onClick={onRunPrediction}
                disabled={isPredicting}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white text-sm font-semibold rounded-lg shadow-lg shadow-indigo-500/20 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
                {isPredicting ? (
                    <Clock className="animate-spin" size={16} />
                ) : (
                    <Zap size={16} />
                )}
                {isPredicting ? 'Analyzing...' : 'AI Predict Trend'}
            </button>
        </div>
      </div>
    </div>
  );
};

export default StockHeader;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles } from 'lucide-react';
import { ChatMessage, Stock } from '../../types';
import { getGeminiChatResponse } from '../../services/geminiService';

interface AssistantProps {
  currentStock: Stock;
}

const Assistant: React.FC<AssistantProps> = ({ currentStock }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'model',
      text: "Hello! I'm Nova. I can analyze market trends and predict stock movements for you. Ask me about any stock in your watchlist.",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await getGeminiChatResponse(input, currentStock);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText || "I'm having trouble analyzing the data right now.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
        console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 border-l border-slate-800 w-80 lg:w-96 shadow-xl z-20">
      <div className="p-4 border-b border-slate-800 bg-slate-900/50 backdrop-blur flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg">
            <Sparkles className="text-white w-4 h-4" />
          </div>
          <div>
            <h2 className="text-sm font-bold text-white">Nova AI Assistant</h2>
            <div className="flex items-center gap-1">
                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                <p className="text-xs text-slate-400">Online</p>
            </div>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex items-start gap-2 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-slate-700' : 'bg-indigo-600'}`}>
              {msg.role === 'user' ? <User size={14} /> : <Bot size={14} />}
            </div>
            <div
              className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
                msg.role === 'user'
                  ? 'bg-slate-800 text-slate-100 rounded-tr-none'
                  : 'bg-indigo-900/30 text-indigo-100 border border-indigo-500/20 rounded-tl-none'
              }`}
            >
              <div className="whitespace-pre-wrap">{msg.text}</div>
              <div className="text-[10px] opacity-50 mt-1 text-right">
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
           <div className="flex items-start gap-2">
              <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center">
                 <Bot size={14} />
              </div>
              <div className="bg-indigo-900/20 px-4 py-3 rounded-2xl rounded-tl-none flex gap-1">
                 <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></span>
                 <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-75"></span>
                 <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></span>
              </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-slate-900 border-t border-slate-800">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ask about price trends..."
            className="w-full bg-slate-800 text-slate-200 text-sm rounded-xl pl-4 pr-12 py-3 border border-slate-700 focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all placeholder:text-slate-500"
          />
          <button
