import React, { useEffect, useState, useMemo } from 'react';
import Sidebar from './components/Layout/Sidebar';
import StockHeader from './components/Dashboard/StockHeader';
import MarketChart from './components/Charts/MarketChart';
import Assistant from './components/Chat/Assistant';
import { WATCHLIST, generateHistory, subscribeToTicker } from './services/stockService';
import { generateAIPrediction } from './services/geminiService';
import { Stock, Candle, TimeFrame, PredictionResult } from './types';
import { Activity, ShieldAlert, Zap } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [watchlist, setWatchlist] = useState<Stock[]>(WATCHLIST);
  const [currentStock, setCurrentStock] = useState<Stock>(WATCHLIST[0]);
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.D1);
  const [history, setHistory] = useState<Candle[]>([]);
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [isPredicting, setIsPredicting] = useState(false);

  // Initialize Data
  useEffect(() => {
    // Load initial history
    const data = generateHistory(currentStock.symbol, timeframe);
    setHistory(data);
    setPrediction(null); // Reset prediction on stock change

    // Subscribe to live updates
    const unsubscribe = subscribeToTicker(currentStock.symbol, (updatedStock) => {
      // Update watchlist state
      setWatchlist(prev => prev.map(s => s.symbol === updatedStock.symbol ? updatedStock : s));

      // Update current stock if selected
      if (updatedStock.symbol === currentStock.symbol) {
        setCurrentStock(updatedStock);
        // Add live point to history
        setHistory(prev => {
          const last = prev[prev.length - 1];
          if (!last) return prev;
          // Simple update logic: update last candle or create new one based on time
          // For demo, just updating close price of last candle
          const newCandle = { ...last, close: updatedStock.price, high: Math.max(last.high, updatedStock.price), low: Math.min(last.low, updatedStock.price) };
          return [...prev.slice(0, -1), newCandle];
        });
      }
    });

    return () => unsubscribe();
  }, [currentStock.symbol, timeframe]);

  const handleStockSelect = (stock: Stock) => {
    setCurrentStock(stock);
    setPrediction(null);
  };

  const runPrediction = async () => {
    setIsPredicting(true);
    const result = await generateAIPrediction(currentStock.symbol, history);
    if (result) {
        setPrediction(result);

        // Append predicted path to chart
        if (result.predictedPath && result.predictedPath.length > 0) {
            const lastTime = new Date(history[history.length - 1].time);
            const predictedCandles: Candle[] = result.predictedPath.map((price: number, index: number) => {
                const newTime = new Date(lastTime);
                newTime.setDate(newTime.getDate() + (index + 1)); // Add days
                return {
                    time: newTime.toISOString(),
                    open: price, 
                    close: price,
                    high: price, 
                    low: price,
                    volume: 0,
                    isPrediction: true
                };
            });
            setHistory(prev => [...prev.filter(c => !c.isPrediction), ...predictedCandles]);
        }
    }
    setIsPredicting(false);
  };

  return (
    <div className="flex h-screen bg-background overflow-hidden font-sans text-slate-100">
      {/* Left Sidebar */}
      <Sidebar 
        watchlist={watchlist} 
        currentStock={currentStock} 
        onSelectStock={handleStockSelect} 
      />

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden relative">
        <main className="flex-1 overflow-y-auto p-6 md:p-8">

          <StockHeader 
            stock={currentStock} 
            timeframe={timeframe} 
            setTimeframe={setTimeframe} 
            onRunPrediction={runPrediction}
            isPredicting={isPredicting}
          />

          <div className="grid grid-cols-1 xl:grid-cols-4 gap-6 mb-6">
            {/* Chart Section */}
            <div className="xl:col-span-4 bg-slate-800/50 border border-slate-700 rounded-xl p-1 shadow-inner h-[500px] relative backdrop-blur-sm">
               {/* Overlay for Prediction Stats */}
               {prediction && (
                   <div className="absolute top-4 left-4 md:left-20 z-10 bg-slate-900/90 border border-indigo-500/50 p-4 rounded-xl shadow-2xl backdrop-blur-md max-w-xs animate-fade-in">
                       <div className="flex items-center gap-2 mb-2">
                           <Zap className="text-yellow-400 fill-current" size={16} />
                           <h3 className="text-sm font-bold text-white uppercase tracking-wider">AI Forecast</h3>
                       </div>
                       <div className="space-y-2">
                           <div className="flex justify-between text-sm">
                               <span className="text-slate-400">Trend:</span>
                               <span className={`font-bold ${prediction.trend === 'UP' ? 'text-emerald-400' : 'text-rose-400'}`}>{prediction.trend}</span>
                           </div>
                           <div className="flex justify-between text-sm">
                               <span className="text-slate-400">Confidence:</span>
                               <span className="text-indigo-300">{prediction.confidence}%</span>
                           </div>
                            <div className="flex justify-between text-sm">
                               <span className="text-slate-400">Risk:</span>
                               <span className={`font-bold ${prediction.riskLevel === 'HIGH' ? 'text-rose-500' : 'text-emerald-500'}`}>{prediction.riskLevel}</span>
                           </div>
                           <div className="mt-2 pt-2 border-t border-slate-700">
                               <p className="text-xs text-slate-300 italic">"{prediction.reasoning}"</p>
                           </div>
                       </div>
                   </div>
               )}
               <MarketChart data={history} symbol={currentStock.symbol} />
            </div>
          </div>

          {/* Key Statistics Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-xs mb-1">Market Cap</div>
                  <div className="text-xl font-bold">2.4T</div>
              </div>
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-xs mb-1">Volume (24h)</div>
                  <div className="text-xl font-bold">45.2M</div>
              </div>
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-xs mb-1">Avg Vol (30d)</div>
                  <div className="text-xl font-bold">38.1M</div>
              </div>
              <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-xs mb-1">P/E Ratio</div>
                  <div className="text-xl font-bold">28.5</div>
              </div>
          </div>

        </main>
      </div>

      {/* Right Chat Sidebar */}
      <Assistant currentStock={currentStock} />
    </div>
  );
};

export default App;

