import React from 'react';
import {
  ResponsiveContainer,
  ComposedChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ReferenceLine,
  Line
} from 'recharts';
import { Candle } from '../../types';

interface MarketChartProps {
  data: Candle[];
  symbol: string;
}

const MarketChart: React.FC<MarketChartProps> = ({ data, symbol }) => {
  const isPositive = data.length > 0 && data[data.length - 1].close >= data[0].close;
  const strokeColor = isPositive ? '#10b981' : '#ef4444'; 
  const fillColor = isPositive ? 'url(#colorUp)' : 'url(#colorDown)';

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' });
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const d = payload[0].payload as Candle;
      return (
        <div className="bg-[#0B0E14]/90 border border-slate-700 p-3 rounded-lg shadow-2xl backdrop-blur-md min-w-[150px]">
          <p className="text-slate-500 text-[10px] font-semibold mb-2 uppercase tracking-wide">{new Date(label).toLocaleString()}</p>
          <div className="flex justify-between items-center mb-1">
             <span className="text-slate-400 text-xs">Price</span>
             <span className={`font-mono text-sm font-bold ${d.isPrediction ? 'text-indigo-400' : 'text-white'}`}>${d.close.toFixed(2)}</span>
          </div>
          {!d.isPrediction && (
            <div className="space-y-0.5 mt-2 pt-2 border-t border-slate-800">
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">Open</span>
                 <span className="text-slate-300 font-mono">${d.open.toFixed(2)}</span>
               </div>
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">High</span>
                 <span className="text-slate-300 font-mono">${d.high.toFixed(2)}</span>
               </div>
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">Low</span>
                 <span className="text-slate-300 font-mono">${d.low.toFixed(2)}</span>
               </div>
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">Vol</span>
                 <span className="text-slate-300 font-mono">{(d.volume / 1000).toFixed(1)}K</span>
               </div>
            </div>
          )}
          {d.isPrediction && (
             <div className="mt-2 pt-2 border-t border-slate-800">
                <p className="text-[10px] text-indigo-400 font-semibold flex items-center gap-1">
                   <span className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></span>
                   AI Projected
                </p>
             </div>
          )}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="w-full h-full min-h-[450px]">
      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart data={data} margin={{ top: 20, right: 0, left: 0, bottom: 0 }}>
          <defs>
            <linearGradient id="colorUp" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#10b981" stopOpacity={0.2} />
              <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="colorDown" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#ef4444" stopOpacity={0.2} />
              <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} opacity={0.5} />
          <XAxis 
            dataKey="time" 
            tickFormatter={formatDate} 
            stroke="#475569" 
            tick={{ fontSize: 11, fill: '#64748b' }} 
            axisLine={false}
            tickLine={false}
            minTickGap={50}
            dy={10}
          />
          <YAxis 
            domain={['auto', 'auto']} 
            orientation="right" 
            stroke="#475569" 
            tick={{ fontSize: 11, fill: '#64748b', fontFamily: 'JetBrains Mono' }} 
            tickFormatter={(val) => val.toFixed(2)}
            axisLine={false}
            tickLine={false}
            dx={5}
          />
          <Tooltip 
            content={<CustomTooltip />} 
            cursor={{ stroke: '#64748b', strokeWidth: 1, strokeDasharray: '4 4' }}
          />

          <Area 
            type="monotone" 
            dataKey="close" 
            stroke={strokeColor} 
            fill={fillColor} 
            strokeWidth={2}
            isAnimationActive={false} // smoother real-time feels
            connectNulls
          />

          <Line 
            type="monotone"
            dataKey="close"
            stroke="#6366f1"
            strokeWidth={2}
            strokeDasharray="5 5"
            dot={false}
            data={data.filter(d => d.isPrediction)}
            isAnimationActive={true}
          />

          {data.find(d => d.isPrediction) && (
             <ReferenceLine x={data.find(d => d.isPrediction)?.time} stroke="#6366f1" strokeDasharray="3 3" />
          )}

        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
};

