import React, { useEffect, useState } from 'react';
import Sidebar from './components/Layout/Sidebar';
import StockHeader from './components/Dashboard/StockHeader';
import MarketChart from './components/Charts/MarketChart';
import Assistant from './components/Chat/Assistant';
import { WATCHLIST, generateHistory, subscribeToTicker } from './services/stockService';
import { generateAIPrediction } from './services/geminiService';
import { Stock, Candle, TimeFrame, PredictionResult } from './types';
import { Activity, Zap, TrendingUp, BarChart3, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [watchlist, setWatchlist] = useState<Stock[]>(WATCHLIST);
  const [currentStock, setCurrentStock] = useState<Stock>(WATCHLIST[0]);
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.D1);
  const [history, setHistory] = useState<Candle[]>([]);
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [isPredicting, setIsPredicting] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(true);

  // Initialize Data
  useEffect(() => {
    const data = generateHistory(currentStock.symbol, timeframe);
    setHistory(data);
    setPrediction(null);

    const unsubscribe = subscribeToTicker(currentStock.symbol, (updatedStock) => {
      setWatchlist(prev => prev.map(s => s.symbol === updatedStock.symbol ? updatedStock : s));

      if (updatedStock.symbol === currentStock.symbol) {
        setCurrentStock(updatedStock);
        setHistory(prev => {
          const last = prev[prev.length - 1];
          if (!last) return prev;
          const newCandle = { ...last, close: updatedStock.price, high: Math.max(last.high, updatedStock.price), low: Math.min(last.low, updatedStock.price) };
          return [...prev.slice(0, -1), newCandle];
        });
      }
    });

    return () => unsubscribe();
  }, [currentStock.symbol, timeframe]);

  const handleStockSelect = (stock: Stock) => {
    setCurrentStock(stock);
    setPrediction(null);
  };

  const runPrediction = async () => {
    setIsPredicting(true);
    const result = await generateAIPrediction(currentStock.symbol, history);
    if (result) {
        setPrediction(result);
        if (result.predictedPath && result.predictedPath.length > 0) {
            const lastTime = new Date(history[history.length - 1].time);
            const predictedCandles: Candle[] = result.predictedPath.map((price: number, index: number) => {
                const newTime = new Date(lastTime);
                newTime.setDate(newTime.getDate() + (index + 1));
                return {
                    time: newTime.toISOString(),
                    open: price, 
                    close: price,
                    high: price, 
                    low: price,
                    volume: 0,
                    isPrediction: true
                };
            });
            setHistory(prev => [...prev.filter(c => !c.isPrediction), ...predictedCandles]);
        }
    }
    setIsPredicting(false);
  };

  return (
    <div className="flex h-screen overflow-hidden font-sans text-slate-100 selection:bg-indigo-500/30">
      <Sidebar 
        watchlist={watchlist} 
        currentStock={currentStock} 
        onSelectStock={handleStockSelect} 
      />

      <div className="flex-1 flex flex-col min-w-0 relative">
        <main className="flex-1 overflow-y-auto p-6 lg:p-10 scroll-smooth">

          <StockHeader 
            stock={currentStock} 
            timeframe={timeframe} 
            setTimeframe={setTimeframe} 
            onRunPrediction={runPrediction}
            isPredicting={isPredicting}
            onToggleChat={() => setIsChatOpen(!isChatOpen)}
            isChatOpen={isChatOpen}
          />

          {/* Main Chart Card */}
          <div className="glass-panel rounded-2xl p-1 shadow-2xl mb-8 relative group">
             {/* Prediction Overlay */}
             {prediction && (
                 <div className="absolute top-6 left-6 z-10 bg-[#0B0E14]/90 border border-indigo-500/30 p-5 rounded-xl shadow-2xl backdrop-blur-md w-72 animate-fade-in ring-1 ring-white/5">
                     <div className="flex items-center gap-2 mb-3 pb-3 border-b border-slate-800">
                         <div className="p-1.5 bg-indigo-500/10 rounded-lg">
                             <Zap className="text-indigo-400 fill-indigo-400/20" size={16} />
                         </div>
                         <h3 className="text-sm font-bold text-white tracking-wide">AI FORECAST</h3>
                     </div>
                     <div className="space-y-3">
                         <div className="flex justify-between items-center text-sm">
                             <span className="text-slate-400 font-medium">Trend Signal</span>
                             <span className={`font-bold px-2 py-0.5 rounded text-xs ${prediction.trend === 'UP' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border border-rose-500/20'}`}>
                                 {prediction.trend}
                             </span>
                         </div>
                         <div className="flex justify-between items-center text-sm">
                             <span className="text-slate-400 font-medium">Confidence</span>
                             <div className="flex items-center gap-2">
                                <div className="h-1.5 w-16 bg-slate-800 rounded-full overflow-hidden">
                                    <div className="h-full bg-indigo-500 rounded-full" style={{ width: `${prediction.confidence}%` }}></div>
                                </div>
                                <span className="text-white font-mono">{prediction.confidence}%</span>
                             </div>
                         </div>
                          <div className="flex justify-between items-center text-sm">
                             <span className="text-slate-400 font-medium">Risk Level</span>
                             <span className={`font-bold ${prediction.riskLevel === 'HIGH' ? 'text-rose-500' : 'text-emerald-500'}`}>{prediction.riskLevel}</span>
                         </div>
                         <div className="mt-2 pt-2 border-t border-slate-800/50">
                             <p className="text-xs text-slate-400 leading-relaxed">
                                <span className="text-indigo-400 font-bold mr-1">Analysis:</span>
                                {prediction.reasoning}
                             </p>
                         </div>
                     </div>
                 </div>
             )}
             <div className="h-[500px] w-full rounded-xl overflow-hidden bg-[#11141d]/50">
                <MarketChart data={history} symbol={currentStock.symbol} />
             </div>
          </div>

          {/* Stats Grid */}
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
              <StatCard label="Market Cap" value="2.42T" icon={<Activity size={18} className="text-indigo-400" />} />
              <StatCard label="Volume (24h)" value="45.2M" icon={<BarChart3 size={18} className="text-emerald-400" />} />
              <StatCard label="P/E Ratio" value="28.5" icon={<TrendingUp size={18} className="text-sky-400" />} />
              <StatCard label="Beta (5Y)" value="1.24" icon={<AlertCircle size={18} className="text-amber-400" />} />
          </div>

        </main>
      </div>

      <Assistant 
        currentStock={currentStock} 
        isOpen={isChatOpen} 
        onClose={() => setIsChatOpen(false)} 
      />
    </div>
  );
};

const StatCard = ({ label, value, icon }: { label: string, value: string, icon: React.ReactNode }) => (
    <div className="bg-[#151921] p-5 rounded-xl border border-slate-800 hover:border-slate-700 transition-colors group">
        <div className="flex items-center justify-between mb-2">
            <span className="text-slate-500 text-xs font-bold uppercase tracking-wider">{label}</span>
