             <div className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-lg text-sm font-bold ${portfolioData.totalGainLoss >= 0 ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
