import React, { useEffect, useState } from 'react';
import Sidebar from './components/Layout/Sidebar';
import MarketOverview from './components/Market/MarketOverview';
import DashboardHome from './components/Dashboard/DashboardHome';
import Portfolio from './components/Portfolio/Portfolio';
import Settings from './components/Settings/Settings';
import Assistant from './components/Chat/Assistant';
import { WATCHLIST, subscribeToTicker } from './services/stockService';
import { Stock, ViewType } from './types';

const App: React.FC = () => {
  const [watchlist, setWatchlist] = useState<Stock[]>(WATCHLIST);
  const [currentStock, setCurrentStock] = useState<Stock>(WATCHLIST[0]);
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isChatOpen, setIsChatOpen] = useState(false);

  // Initialize Data Subscription
  useEffect(() => {
    // We subscribe to all tickers in the watchlist to simulate a live market environment across all views
    const unsubscribers = watchlist.map(stock => {
      return subscribeToTicker(stock.symbol, (updatedStock) => {
        setWatchlist(prev => prev.map(s => s.symbol === updatedStock.symbol ? updatedStock : s));

        // If this updated stock is the one currently selected in the market view, update it
        if (updatedStock.symbol === currentStock.symbol) {
          setCurrentStock(updatedStock);
        }
      });
    });

    return () => {
      unsubscribers.forEach(unsub => unsub());
    };
  }, [currentStock.symbol]); 
  // Dependency note: simplistic approach. Ideally we don't re-subscribe on currentStock change, 
  // but for this demo, keeping the logic simple is fine. The service handles duplicate subscriptions gracefully.

  const handleStockSelect = (stock: Stock) => {
    setCurrentStock(stock);
    // Note: We don't force switch to 'market' view here automatically unless intended.
    // Sidebar handles the view switch.
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return <DashboardHome watchlist={watchlist} onNavigate={setCurrentView} />;
      case 'market':
        return (
          <MarketOverview 
            currentStock={currentStock} 
            isChatOpen={isChatOpen} 
            onToggleChat={() => setIsChatOpen(!isChatOpen)} 
          />
        );
      case 'portfolio':
        return <Portfolio watchlist={watchlist} />;
      case 'settings':
        return <Settings />;
      default:
        return <DashboardHome watchlist={watchlist} onNavigate={setCurrentView} />;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden font-sans text-slate-100 selection:bg-indigo-500/30">
      <Sidebar 
        watchlist={watchlist} 
        currentStock={currentStock} 
        onSelectStock={handleStockSelect} 
        currentView={currentView}
        onViewChange={setCurrentView}
      />

      <div className="flex-1 flex flex-col min-w-0 relative">
        <main className="flex-1 overflow-y-auto p-6 lg:p-10 scroll-smooth">
          {renderView()}
        </main>
      </div>

      <Assistant 
        currentStock={currentStock} 
        isOpen={isChatOpen} 
        onClose={() => setIsChatOpen(false)} 
      />
    </div>
  );
};

export default App;

