interface MarketChartProps {
  data: Candle[];
  symbol: string;
}

const MarketChart: React.FC<MarketChartProps> = ({ data, symbol }) => {
  const isPositive = data.length > 0 && data[0].close <= (data.find(d => d.isPrediction)?.close ?? data[data.length - 1].close);
  // Color based on overall trend or just the historical part? 
  // Usually daily change color. Let's stick to last historical vs first historical or just last price move.
  // Simple check: Last historical vs First historical
  const historicalData = data.filter(d => !d.isPrediction);
  const predictionData = data.filter(d => d.isPrediction);

  const lastHistorical = historicalData[historicalData.length - 1];
  const isTrendPositive = lastHistorical && historicalData[0] ? lastHistorical.close >= historicalData[0].close : true;

  const strokeColor = isTrendPositive ? '#10b981' : '#ef4444'; 
  const fillColor = isTrendPositive ? 'url(#colorUp)' : 'url(#colorDown)';

  // Prepare prediction data to connect with historical
  const predictionDisplayData = [...predictionData];
  if (lastHistorical && predictionData.length > 0) {
    predictionDisplayData.unshift(lastHistorical);
  }

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' });
