import React from 'react';
import {
  ResponsiveContainer,
  ComposedChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ReferenceLine,
  Line
} from 'recharts';
import { Candle } from '../../types';

interface MarketChartProps {
  data: Candle[];
  symbol: string;
  isDarkMode?: boolean;
}

const MarketChart: React.FC<MarketChartProps> = ({ data, symbol, isDarkMode = true }) => {
  // Split data into historical and prediction
  const historicalData = data.filter(d => !d.isPrediction);
  const predictionData = data.filter(d => d.isPrediction);

  const lastHistorical = historicalData[historicalData.length - 1];

  // Determine trend color based on historical performance
  const isTrendPositive = lastHistorical && historicalData[0] 
    ? lastHistorical.close >= historicalData[0].close 
    : true;

  const strokeColor = isTrendPositive ? '#10b981' : '#ef4444'; 
  const fillColor = isTrendPositive ? 'url(#colorUp)' : 'url(#colorDown)';

  // Prepare prediction data to connect seamlessy with historical tail
  const predictionDisplayData = [...predictionData];
  if (lastHistorical && predictionData.length > 0) {
    predictionDisplayData.unshift(lastHistorical);
  }

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' });
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      // Find the payload that matches the mouse position (priority to prediction if overlapping)
      const d = payload[0].payload as Candle;
      return (
        <div className="bg-white/90 dark:bg-[#0B0E14]/90 border border-slate-200 dark:border-slate-700 p-3 rounded-lg shadow-2xl backdrop-blur-md min-w-[150px] animate-in fade-in zoom-in-95 duration-200">
          <p className="text-slate-500 text-[10px] font-semibold mb-2 uppercase tracking-wide font-mono">{new Date(label).toLocaleString()}</p>
          <div className="flex justify-between items-center mb-1">
             <span className="text-slate-400 text-xs">Price</span>
             <span className={`font-mono text-sm font-bold ${d.isPrediction ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-900 dark:text-white'}`}>${d.close.toFixed(2)}</span>
          </div>
          {!d.isPrediction && (
            <div className="space-y-0.5 mt-2 pt-2 border-t border-slate-200 dark:border-slate-800">
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">Open</span>
                 <span className="text-slate-700 dark:text-slate-300 font-mono">${d.open.toFixed(2)}</span>
               </div>
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">High</span>
                 <span className="text-slate-700 dark:text-slate-300 font-mono">${d.high.toFixed(2)}</span>
               </div>
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">Low</span>
                 <span className="text-slate-700 dark:text-slate-300 font-mono">${d.low.toFixed(2)}</span>
               </div>
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">Vol</span>
                 <span className="text-slate-700 dark:text-slate-300 font-mono">{(d.volume / 1000).toFixed(1)}K</span>
               </div>
            </div>
          )}
          {d.isPrediction && (
             <div className="mt-2 pt-2 border-t border-slate-200 dark:border-slate-800 bg-indigo-50/50 dark:bg-indigo-500/5 -mx-3 -mb-3 px-3 py-2">
                <p className="text-[10px] text-indigo-600 dark:text-indigo-400 font-bold flex items-center gap-1.5 uppercase tracking-wider">
                   <ZapIcon />
                   AI Forecast
                </p>
             </div>
          )}
        </div>
      );
    }
    return null;
  };

  const ZapIcon = () => (
    <svg width="10" height="10" viewBox="0 0 24 24" fill="currentColor" className="animate-pulse">
      <polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2" />
    </svg>
  );

  // Theme Variables
  const gridColor = isDarkMode ? "#1e293b" : "#e2e8f0";
  const axisColor = isDarkMode ? "#475569" : "#94a3b8";
  const axisTextColor = isDarkMode ? "#64748b" : "#64748b";

  return (
    <div className="w-full h-full min-h-[450px]">
      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart data={data} margin={{ top: 20, right: 0, left: 0, bottom: 0 }}>
          <defs>
            <linearGradient id="colorUp" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="colorDown" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
            </linearGradient>

            {/* Pattern for Prediction Area */}
            <pattern id="pattern-stripe" width="8" height="8" patternUnits="userSpaceOnUse" patternTransform="rotate(45)">
              <rect width="2" height="8" transform="translate(0,0)" fill="#6366f1" opacity="0.15"></rect>
            </pattern>

            {/* Glow Filter for Prediction Line */}
            <filter id="glow" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="3" result="coloredBlur" />
              <feMerge>
                <feMergeNode in="coloredBlur" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          </defs>

          <CartesianGrid strokeDasharray="3 3" stroke={gridColor} vertical={false} opacity={0.4} />

          <XAxis 
            dataKey="time" 
            tickFormatter={formatDate} 
            stroke={axisColor} 
            tick={{ fontSize: 11, fill: axisTextColor }} 
            axisLine={false}
            tickLine={false}
            minTickGap={60}
            dy={10}
          />

          <YAxis 
            domain={['auto', 'auto']} 
            orientation="right" 
            stroke={axisColor} 
            tick={{ fontSize: 11, fill: axisTextColor, fontFamily: 'JetBrains Mono' }} 
            tickFormatter={(val) => val.toFixed(2)}
            axisLine={false}
            tickLine={false}
            dx={5}
          />

          <Tooltip 
            content={<CustomTooltip />} 
            cursor={{ stroke: axisColor, strokeWidth: 1, strokeDasharray: '4 4' }}
          />

          {/* Historical Data Area */}
          <Area 
            type="monotone" 
            dataKey="close" 
            data={historicalData}
            stroke={strokeColor} 
            fill={fillColor} 
            strokeWidth={2}
            isAnimationActive={false}
            connectNulls
          />

          {/* Prediction Line Overlay with Glow */}
          <Line 
            type="monotone"
            dataKey="close"
            data={predictionDisplayData}
            stroke="#818cf8"
            strokeWidth={3}
            strokeDasharray="4 4"
            dot={{ r: 4, fill: "#818cf8", strokeWidth: 2, stroke: isDarkMode ? "#0B0E14" : "#ffffff" }}
            activeDot={{ r: 7, fill: "#a5b4fc", stroke: "#6366f1", strokeWidth: 2 }}
            isAnimationActive={true}
            animationDuration={1500}
            filter="url(#glow)"
          />

          {/* Prediction Area Highlight */}
          {predictionData.length > 0 && (
             <Area
                type="monotone"
                dataKey="close"
                data={predictionDisplayData}
                stroke="none"
                fill="url(#pattern-stripe)"
                isAnimationActive={true}
                animationDuration={1500}
             />
          )}

          {/* Divider Line */}
          {predictionData.length > 0 && lastHistorical && (
             <ReferenceLine 
                x={lastHistorical.time} 
                stroke="#6366f1" 
                strokeDasharray="3 3" 
                strokeOpacity={0.8}
             >
                <text 
                  x={0} 
                  y={0} 
                  dy={-10} 
                  dx={5} 
                  fill="#818cf8" 
                  fontSize="10" 
                  fontWeight="bold" 
                  textAnchor="start"
                  transform={`translate(0, 20)`} // Adjust vertically if needed but ReferenceLine handles positioning on X
                >
                   LIVE
                </text>
             </ReferenceLine>
          )}

        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
};

