interface MarketChartProps {
  data: Candle[];
  symbol: string;
  isDarkMode?: boolean;
  comparisons?: string[];
}

const COMPARISON_COLORS = ['#f59e0b', '#0ea5e9', '#ec4899', '#8b5cf6']; // Amber, Sky, Pink, Violet

const MarketChart: React.FC<MarketChartProps> = ({ data, symbol, isDarkMode = true, comparisons = [] }) => {
  // Split data into historical and prediction
  const historicalData = data.filter(d => !d.isPrediction);
  const predictionData = data.filter(d => d.isPrediction);

  const lastHistorical = historicalData[historicalData.length - 1];

  // Determine trend color based on historical performance
  const isTrendPositive = lastHistorical && historicalData[0] 
    ? lastHistorical.close >= historicalData[0].close 
    : true;

  const strokeColor = isTrendPositive ? '#10b981' : '#ef4444'; 
  const fillColor = isTrendPositive ? 'url(#colorUp)' : 'url(#colorDown)';

  // Prepare prediction data to connect seamlessy with historical tail
  const predictionDisplayData = [...predictionData];
  if (lastHistorical && predictionData.length > 0) {
    predictionDisplayData.unshift(lastHistorical);
  }

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' });
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      // Find the main payload (current stock)
      const d = payload.find((p: any) => p.dataKey === 'close')?.payload as Candle || payload[0].payload;

      return (
        <div className="bg-white/95 dark:bg-[#0B0E14]/95 border border-slate-200 dark:border-slate-700 p-3 rounded-lg shadow-2xl backdrop-blur-md min-w-[180px] animate-in fade-in zoom-in-95 duration-200">
          <p className="text-slate-500 text-[10px] font-semibold mb-2 uppercase tracking-wide font-mono border-b border-slate-200 dark:border-slate-800 pb-1">
            {new Date(label).toLocaleString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
          </p>

          {/* Main Stock */}
          <div className="flex justify-between items-center mb-1">
             <div className="flex items-center gap-2">
                <span className={`w-2 h-2 rounded-full ${d.isPrediction ? 'bg-indigo-500 animate-pulse' : (isTrendPositive ? 'bg-emerald-500' : 'bg-rose-500')}`}></span>
                <span className="text-slate-500 dark:text-slate-400 text-xs font-bold">{symbol}</span>
             </div>
             <span className={`font-mono text-sm font-bold ${d.isPrediction ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-900 dark:text-white'}`}>
