            <linearGradient id="colorDown" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
            </linearGradient>

            {/* Pattern for Prediction Area */}
            <pattern id="pattern-stripe" width="8" height="8" patternUnits="userSpaceOnUse" patternTransform="rotate(45)">
              <rect width="2" height="8" transform="translate(0,0)" fill="#6366f1" opacity="0.15"></rect>
            </pattern>

            {/* Glow Filter for Prediction Line */}
            <filter id="glow" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="3" result="coloredBlur" />
              <feMerge>
                <feMergeNode in="coloredBlur" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          </defs>

          <CartesianGrid strokeDasharray="3 3" stroke={gridColor} vertical={false} opacity={0.4} />

          <XAxis 
            dataKey="time" 
            tickFormatter={formatDate} 
            stroke={axisColor} 
            tick={{ fontSize: 11, fill: axisTextColor }} 
            axisLine={false}
            tickLine={false}
            minTickGap={60}
            dy={10}
          />

          <YAxis 
            domain={['auto', 'auto']} 
            orientation="right" 
            stroke={axisColor} 
            tick={{ fontSize: 11, fill: axisTextColor, fontFamily: 'JetBrains Mono' }} 
            tickFormatter={(val) => val.toFixed(2)}
            axisLine={false}
            tickLine={false}
            dx={5}
          />

          <Tooltip 
            content={<CustomTooltip />} 
            cursor={{ stroke: axisColor, strokeWidth: 1, strokeDasharray: '4 4' }}
          />

          {/* Historical Data Area (Main Stock) */}
          <Area 
            type="monotone" 
            dataKey="close" 
            data={historicalData}
            stroke={strokeColor} 
            fill={fillColor} 
            strokeWidth={2}
            isAnimationActive={false}
            connectNulls
          />

          {/* Comparison Lines */}
          {comparisons.map((compSymbol, idx) => (
            <Line
              key={compSymbol}
              type="monotone"
              dataKey={compSymbol}
              stroke={COMPARISON_COLORS[idx % COMPARISON_COLORS.length]}
              strokeWidth={2}
              dot={false}
              activeDot={{ r: 4, strokeWidth: 0 }}
              isAnimationActive={true}
              connectNulls
            />
          ))}

          {/* Prediction Line Overlay with Glow */}
          <Line 
            type="monotone"
            dataKey="close"
            data={predictionDisplayData}
            stroke="#818cf8"
            strokeWidth={3}
            strokeDasharray="4 4"
            dot={{ r: 4, fill: "#818cf8", strokeWidth: 2, stroke: isDarkMode ? "#0B0E14" : "#ffffff" }}
            activeDot={{ r: 7, fill: "#a5b4fc", stroke: "#6366f1", strokeWidth: 2 }}
            isAnimationActive={true}
            animationDuration={1500}
            filter="url(#glow)"
          />

          {/* Prediction Area Highlight */}
          {predictionData.length > 0 && (
             <Area
                type="monotone"
                dataKey="close"
                data={predictionDisplayData}
                stroke="none"
                fill="url(#pattern-stripe)"
                isAnimationActive={true}
                animationDuration={1500}
             />
          )}

          {/* Divider Line */}
          {predictionData.length > 0 && lastHistorical && (
             <ReferenceLine 
                x={lastHistorical.time} 
                stroke="#6366f1" 
                strokeDasharray="3 3" 
                strokeOpacity={0.8}
             >
                <text 
                  x={0} 
                  y={0} 
                  dy={-10} 
                  dx={5} 
                  fill="#818cf8" 
                  fontSize="10" 
                  fontWeight="bold" 
                  textAnchor="start"
                  transform={`translate(0, 20)`} // Adjust vertically if needed but ReferenceLine handles positioning on X
                >
                   LIVE
                </text>
             </ReferenceLine>
          )}

        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
};

