// Helper to calculate SMA
const calculateSMA = (data: Candle[], period: number, index: number): number | undefined => {
  if (index < period - 1) return undefined;
  let sum = 0;
  for (let i = 0; i < period; i++) {
    sum += data[index - i].close;
  }
  return sum / period;
};

// Helper to calculate RSI
const calculateRSI = (data: Candle[], period: number = 14) => {
  let gains = 0;
  let losses = 0;

  // First average
  for (let i = 1; i <= period; i++) {
    const change = data[i].close - data[i - 1].close;
    if (change > 0) gains += change;
    else losses -= change;
  }

  let avgGain = gains / period;
  let avgLoss = losses / period;

  // Subsequent values
  for (let i = period + 1; i < data.length; i++) {
    const change = data[i].close - data[i - 1].close;
    if (change > 0) {
      avgGain = (avgGain * (period - 1) + change) / period;
      avgLoss = (avgLoss * (period - 1)) / period;
    } else {
      avgGain = (avgGain * (period - 1)) / period;
      avgLoss = (avgLoss * (period - 1) - change) / period;
    }

    const rs = avgGain / (avgLoss === 0 ? 1 : avgLoss);
    data[i].rsi = 100 - (100 / (1 + rs));
  }
};

// Helper to calculate MACD (Simplified)
const calculateMACD = (data: Candle[]) => {
  // Approximate EMAs with SMAs for this mock data generator to keep it light
  // Real implementation would use recursive EMA
  for (let i = 26; i < data.length; i++) {
    const ema12 = calculateSMA(data, 12, i) || data[i].close;
    const ema26 = calculateSMA(data, 26, i) || data[i].close;
    const macd = ema12 - ema26;
    data[i].macd = macd;
  }

  // Signal line (9 period SMA of MACD)
  for (let i = 35; i < data.length; i++) {
     let sum = 0;
     for(let j=0; j<9; j++) {
       sum += data[i-j].macd || 0;
     }
     const signal = sum / 9;
     data[i].macdSignal = signal;
     data[i].macdHist = (data[i].macd || 0) - signal;
  }
};

// Helper to generate random candles
export const generateHistory = (symbol: string, timeframe: TimeFrame): Candle[] => {
  const data: Candle[] = [];
  let points = 100;
  let intervalMinutes = 60; // Default 1H

  switch (timeframe) {
    case TimeFrame.D1: points = 48; intervalMinutes = 30; break; // Every 30 mins
    case TimeFrame.W1: points = 84; intervalMinutes = 120; break;
    case TimeFrame.M1: points = 30; intervalMinutes = 1440; break; // Daily
    case TimeFrame.M3: points = 90; intervalMinutes = 1440; break;
    case TimeFrame.Y1: points = 52; intervalMinutes = 10080; break; // Weekly
  }

  // Increase points slightly to allow indicators to warm up, then slice
  const warmupPoints = 35;
  const totalPoints = points + warmupPoints;

  // Seed price based on symbol
  let currentPrice = WATCHLIST.find(s => s.symbol === symbol)?.price || 100;
  // Start date back in time
  let time = new Date();
  time.setMinutes(time.getMinutes() - (totalPoints * intervalMinutes));

  for (let i = 0; i < totalPoints; i++) {
    const volatility = currentPrice * 0.02; // 2% volatility
    const change = (Math.random() - 0.5) * volatility;

    const open = currentPrice;
    const close = currentPrice + change;
    const high = Math.max(open, close) + Math.random() * (volatility * 0.5);
    const low = Math.min(open, close) - Math.random() * (volatility * 0.5);
    const volume = Math.floor(Math.random() * 1000000) + 500000;

    const candle: Candle = {
      time: time.toISOString(),
      open,
      high,
      low,
      close,
      volume,
      isPrediction: false
    };

    data.push(candle);

    currentPrice = close;
    time = new Date(time.getTime() + intervalMinutes * 60000);
  }

  // Calculate Indicators
  for (let i = 0; i < data.length; i++) {
    data[i].ma7 = calculateSMA(data, 7, i);
    data[i].ma25 = calculateSMA(data, 25, i);
  }
  calculateRSI(data);
  calculateMACD(data);

  // Return only the requested points, slicing off warmup
  return data.slice(warmupPoints);
};

// Simulate live updates
type Listener = (stock: Stock) => void;
const listeners: Map<string, Listener[]> = new Map();

export const subscribeToTicker = (symbol: string, callback: Listener) => {
  if (!listeners.has(symbol)) {
    listeners.set(symbol, []);
  }
  listeners.get(symbol)?.push(callback);

  // Start simulation if not already running globally (mock implementation simplified)
  const interval = setInterval(() => {
    const stock = WATCHLIST.find(s => s.symbol === symbol);
    if (stock) {
      // Random walk
      const delta = (Math.random() - 0.45) * (stock.price * 0.002);
      stock.price += delta;
      stock.change += delta;
      stock.changePercent = (stock.change / (stock.price - stock.change)) * 100;

      callback({ ...stock });
    }
  }, 3000);

  return () => {
    const list = listeners.get(symbol);
    if (list) {
      const index = list.indexOf(callback);
      if (index > -1) list.splice(index, 1);
    }
    clearInterval(interval);
  };
};

import React, { useEffect, useState, useMemo } from 'react';
import { Activity, BarChart3, TrendingUp, AlertCircle, Zap, Layers, Check, SlidersHorizontal } from 'lucide-react';
import StockHeader from '../Dashboard/StockHeader';
import MarketChart from '../Charts/MarketChart';
import { generateHistory, WATCHLIST } from '../../services/stockService';
import { generateAIPrediction } from '../../services/geminiService';
import { Stock, Candle, TimeFrame, PredictionResult } from '../../types';

interface MarketOverviewProps {
  currentStock: Stock;
  isChatOpen: boolean;
  onToggleChat: () => void;
  isDarkMode?: boolean;
}

const MarketOverview: React.FC<MarketOverviewProps> = ({ currentStock, isChatOpen, onToggleChat, isDarkMode = true }) => {
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.D1);
  const [history, setHistory] = useState<Candle[]>([]);
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);
  const [isPredicting, setIsPredicting] = useState(false);

  // Comparison State
  const [selectedComparisons, setSelectedComparisons] = useState<string[]>([]);
  const [comparisonData, setComparisonData] = useState<Record<string, Candle[]>>({});
  const [isCompareMenuOpen, setIsCompareMenuOpen] = useState(false);

  // Indicator State
  const [indicators, setIndicators] = useState({
    ma: true,
    rsi: false,
    macd: false
  });

  // Initialize Data when stock or timeframe changes
  useEffect(() => {
    const data = generateHistory(currentStock.symbol, timeframe);
    setHistory(data);
    setPrediction(null);
    // Clear comparisons when switching main stock to avoid confusion
    setSelectedComparisons([]); 
    setComparisonData({});
  }, [currentStock.symbol, timeframe]);

  // Fetch data for selected comparisons
  useEffect(() => {
    const newComparisonData: Record<string, Candle[]> = {};
    selectedComparisons.forEach(symbol => {
      newComparisonData[symbol] = generateHistory(symbol, timeframe);
    });
    setComparisonData(newComparisonData);
  }, [selectedComparisons, timeframe]);

  // Update history when currentStock price changes (live update simulation)
  useEffect(() => {
    setHistory(prev => {
      if (prev.length === 0) return prev;
      const last = prev[prev.length - 1];

      const realHistory = prev.filter(c => !c.isPrediction);
      const lastReal = realHistory[realHistory.length - 1];

      if (!lastReal) return prev;

      const newCandle = { 
        ...lastReal, 
        close: currentStock.price, 
        high: Math.max(lastReal.high, currentStock.price), 
        low: Math.min(lastReal.low, currentStock.price) 
      };

      const predictions = prev.filter(c => c.isPrediction);
      return [...realHistory.slice(0, -1), newCandle, ...predictions];
    });
  }, [currentStock.price]);

  const runPrediction = async () => {
    setIsPredicting(true);
    const result = await generateAIPrediction(currentStock.symbol, history);
    if (result) {
        setPrediction(result);
        if (result.predictedPath && result.predictedPath.length > 0) {
            const lastTime = new Date(history[history.length - 1].time);
            const predictedCandles: Candle[] = result.predictedPath.map((price: number, index: number) => {
                const newTime = new Date(lastTime);
                newTime.setDate(newTime.getDate() + (index + 1));
                return {
                    time: newTime.toISOString(),
                    open: price, 
                    close: price,
                    high: price, 
                    low: price,
                    volume: 0,
                    isPrediction: true
                };
            });
            setHistory(prev => [...prev.filter(c => !c.isPrediction), ...predictedCandles]);
        }
    }
    setIsPredicting(false);
  };

  const toggleComparison = (symbol: string) => {
    setSelectedComparisons(prev => 
      prev.includes(symbol) 
        ? prev.filter(s => s !== symbol)
        : [...prev, symbol]
    );
  };

  const toggleIndicator = (key: keyof typeof indicators) => {
    setIndicators(prev => ({ ...prev, [key]: !prev[key] }));
  };

  // Merge Data for Chart
  const mergedChartData = useMemo(() => {
    return history.map((candle, index) => {
      const mergedPoint: any = { ...candle };
      selectedComparisons.forEach(symbol => {
        const compCandles = comparisonData[symbol];
        if (compCandles && compCandles[index]) {
          mergedPoint[symbol] = compCandles[index].close;
        }
      });
      return mergedPoint;
    });
  }, [history, comparisonData, selectedComparisons]);

  return (
    <div className="animate-fade-in pb-10">
      <StockHeader 
        stock={currentStock} 
        timeframe={timeframe} 
        setTimeframe={setTimeframe} 
        onRunPrediction={runPrediction}
        isPredicting={isPredicting}
        onToggleChat={onToggleChat}
        isChatOpen={isChatOpen}
      />

      {/* Main Chart Card */}
      <div className="glass-panel rounded-2xl p-1 shadow-xl mb-6 lg:mb-8 relative group bg-surface">

          {/* Chart Controls Overlay */}
          <div className="absolute top-4 right-4 z-20 flex items-center gap-2">
             {/* Indicator Toggles */}
             <div className="flex bg-white/80 dark:bg-[#0B0E14]/80 backdrop-blur border border-border rounded-lg p-0.5">
                <button 
                  onClick={() => toggleIndicator('ma')}
                  className={`px-2 py-1 text-[10px] font-bold rounded transition-colors ${indicators.ma ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-900 dark:hover:text-slate-300'}`}
                >
                  MA
                </button>
                <button 
                  onClick={() => toggleIndicator('rsi')}
                  className={`px-2 py-1 text-[10px] font-bold rounded transition-colors ${indicators.rsi ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-900 dark:hover:text-slate-300'}`}
                >
                  RSI
                </button>
                <button 
                  onClick={() => toggleIndicator('macd')}
                  className={`px-2 py-1 text-[10px] font-bold rounded transition-colors ${indicators.macd ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-900 dark:hover:text-slate-300'}`}
                >
                  MACD
                </button>
             </div>

             {/* Compare Menu */}
             <div className="relative">
                <button 
                  onClick={() => setIsCompareMenuOpen(!isCompareMenuOpen)}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all border ${
                    selectedComparisons.length > 0
                      ? 'bg-indigo-600 text-white border-indigo-500' 
                      : 'bg-white/80 dark:bg-[#0B0E14]/80 text-slate-600 dark:text-slate-300 border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800'
                  }`}
                >
                  <Layers size={14} />
                  <span>Compare {selectedComparisons.length > 0 && `(${selectedComparisons.length})`}</span>
                </button>

                {isCompareMenuOpen && (
                  <>
                    <div className="fixed inset-0 z-10" onClick={() => setIsCompareMenuOpen(false)}></div>
                    <div className="absolute right-0 mt-2 w-48 bg-white dark:bg-[#1a1f2e] border border-border rounded-xl shadow-xl z-20 py-1 animate-in fade-in zoom-in-95 duration-100">
                       <div className="px-3 py-2 text-[10px] font-bold text-slate-500 uppercase tracking-wider border-b border-border">
                         Overlay Stock
                       </div>
                       {WATCHLIST.filter(s => s.symbol !== currentStock.symbol).map(stock => (
                         <button
                           key={stock.symbol}
                           onClick={() => toggleComparison(stock.symbol)}
                           className="w-full flex items-center justify-between px-3 py-2 text-sm text-left hover:bg-slate-50 dark:hover:bg-white/5 transition-colors"
                         >
                           <span className="text-slate-700 dark:text-slate-200">{stock.symbol}</span>
                           {selectedComparisons.includes(stock.symbol) && (
                             <Check size={14} className="text-indigo-500" />
                           )}
                         </button>
                       ))}
                    </div>
                  </>
                )}
             </div>
          </div>

          {/* Prediction Overlay */}
          {prediction && (
              <div className="absolute top-4 left-4 lg:top-6 lg:left-6 z-10 bg-surface/95 border border-indigo-500/30 p-4 lg:p-5 rounded-xl shadow-2xl backdrop-blur-md w-64 lg:w-72 animate-fade-in ring-1 ring-white/5 dark:ring-white/5">
                  <div className="flex items-center gap-2 mb-3 pb-3 border-b border-border">
                      <div className="p-1.5 bg-indigo-500/10 rounded-lg">
                          <Zap className="text-indigo-500 dark:text-indigo-400 fill-indigo-400/20" size={16} />
                      </div>
                      <h3 className="text-sm font-bold text-slate-900 dark:text-white tracking-wide">AI FORECAST</h3>
                  </div>
                  <div className="space-y-3">
                      <div className="flex justify-between items-center text-sm">
                          <span className="text-slate-500 dark:text-slate-400 font-medium">Trend Signal</span>
                          <span className={`font-bold px-2 py-0.5 rounded text-xs ${prediction.trend === 'UP' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-600 dark:text-rose-400 border border-rose-500/20'}`}>
                              {prediction.trend}
                          </span>
                      </div>
                      <div className="flex justify-between items-center text-sm">
                          <span className="text-slate-500 dark:text-slate-400 font-medium">Confidence</span>
                          <div className="flex items-center gap-2">
                            <div className="h-1.5 w-12 lg:w-16 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                                <div className="h-full bg-indigo-500 rounded-full" style={{ width: `${prediction.confidence}%` }}></div>
                            </div>
                            <span className="text-slate-900 dark:text-white font-mono">{prediction.confidence}%</span>
                          </div>
                      </div>
                      <div className="flex justify-between items-center text-sm">
                          <span className="text-slate-500 dark:text-slate-400 font-medium">Risk Level</span>
                          <span className={`font-bold ${prediction.riskLevel === 'HIGH' ? 'text-rose-500' : 'text-emerald-500'}`}>{prediction.riskLevel}</span>
                      </div>
                      <div className="mt-2 pt-2 border-t border-border">
                          <p className="text-xs text-slate-500 dark:text-slate-400 leading-relaxed">
                            <span className="text-indigo-500 dark:text-indigo-400 font-bold mr-1">Analysis:</span>
                            {prediction.reasoning}
                          </p>
                      </div>
                  </div>
              </div>
          )}

          {/* Responsive Height Container */}
          <div className="h-[500px] w-full rounded-xl overflow-hidden bg-white/50 dark:bg-[#11141d]/50 flex flex-col">
            <MarketChart 
              data={mergedChartData} 
              symbol={currentStock.symbol} 
              isDarkMode={isDarkMode} 
              comparisons={selectedComparisons}
              indicators={indicators}
            />
          </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 lg:gap-4">
          <StatCard label="Market Cap" value="2.42T" icon={<Activity size={18} className="text-indigo-500 dark:text-indigo-400" />} />
          <StatCard label="Volume (24h)" value="45.2M" icon={<BarChart3 size={18} className="text-emerald-500 dark:text-emerald-400" />} />
          <StatCard label="P/E Ratio" value="28.5" icon={<TrendingUp size={18} className="text-sky-500 dark:text-sky-400" />} />
          <StatCard label="Beta (5Y)" value="1.24" icon={<AlertCircle size={18} className="text-amber-500 dark:text-amber-400" />} />
      </div>
    </div>
  );
};

