            return (
              <div key={compSymbol} className="flex justify-between items-center mb-1">
                 <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full" style={{ backgroundColor: COMPARISON_COLORS[idx % COMPARISON_COLORS.length] }}></span>
                    <span className="text-slate-500 dark:text-slate-400 text-xs font-bold">{compSymbol}</span>
                 </div>
                 <span className="font-mono text-sm font-medium text-slate-700 dark:text-slate-300">
                    ${compValue.toFixed(2)}
                 </span>
              </div>
            );
          })}

          {/* Indicators Info */}
          <div className="mt-2 pt-2 border-t border-slate-200 dark:border-slate-800 space-y-1">
             {indicators.ma && d.ma7 && (
                <div className="flex justify-between items-center text-[10px]">
                   <span className="text-orange-500 font-bold">MA7</span>
                   <span className="font-mono text-slate-700 dark:text-slate-300">{d.ma7.toFixed(2)}</span>
                </div>
             )}
             {indicators.ma && d.ma25 && (
                <div className="flex justify-between items-center text-[10px]">
                   <span className="text-blue-500 font-bold">MA25</span>
                   <span className="font-mono text-slate-700 dark:text-slate-300">{d.ma25.toFixed(2)}</span>
                </div>
             )}
             {indicators.rsi && d.rsi && (
                <div className="flex justify-between items-center text-[10px]">
                   <span className="text-purple-500 font-bold">RSI</span>
                   <span className="font-mono text-slate-700 dark:text-slate-300">{d.rsi.toFixed(2)}</span>
                </div>
             )}
          </div>

          {!d.isPrediction && (
            <div className="space-y-0.5 mt-2 pt-2 border-t border-slate-200 dark:border-slate-800 opacity-80">
               <div className="flex justify-between text-[10px]">
                 <span className="text-slate-500">Vol</span>
                 <span className="text-slate-700 dark:text-slate-300 font-mono">{(d.volume / 1000).toFixed(1)}K</span>
               </div>
            </div>
          )}

          {d.isPrediction && (
             <div className="mt-2 pt-2 border-t border-slate-200 dark:border-slate-800 bg-indigo-50/50 dark:bg-indigo-500/5 -mx-3 -mb-3 px-3 py-2">
                <p className="text-[10px] text-indigo-600 dark:text-indigo-400 font-bold flex items-center gap-1.5 uppercase tracking-wider">
                   <ZapIcon />
                   AI Forecast
                </p>
             </div>
          )}
        </div>
      );
    }
    return null;
  };

  // Theme Variables
  const gridColor = isDarkMode ? "#1e293b" : "#e2e8f0";
  const axisColor = isDarkMode ? "#475569" : "#94a3b8";
  const axisTextColor = isDarkMode ? "#64748b" : "#64748b";

  return (
    <div className="w-full h-full flex flex-col relative">
      <defs>
        <linearGradient id="colorUp" x1="0" y1="0" x2="0" y2="1">
          <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
          <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
        </linearGradient>
        <linearGradient id="colorDown" x1="0" y1="0" x2="0" y2="1">
          <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
          <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
        </linearGradient>
        <pattern id="pattern-stripe" width="8" height="8" patternUnits="userSpaceOnUse" patternTransform="rotate(45)">
          <rect width="2" height="8" transform="translate(0,0)" fill="#6366f1" opacity="0.15"></rect>
        </pattern>
        <filter id="glow" x="-50%" y="-50%" width="200%" height="200%">
          <feGaussianBlur stdDeviation="3" result="coloredBlur" />
          <feMerge>
            <feMergeNode in="coloredBlur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
      </defs>

      {/* Quick Trade Panel Overlay */}
      <div className="absolute top-4 left-1/2 -translate-x-1/2 z-10 flex items-center gap-4 bg-white/90 dark:bg-[#1a1f2e]/90 backdrop-blur-md p-2 rounded-xl border border-slate-200 dark:border-slate-700 shadow-xl transition-opacity animate-in fade-in slide-in-from-top-4 duration-500">
         <div className="hidden sm:flex items-center gap-3 px-2 border-r border-slate-200 dark:border-slate-700 pr-4">
             <div className="flex flex-col items-end">
                <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">{symbol}</span>
                <div className="flex items-center gap-1.5">
                   {isPriceUp ? <TrendingUp size={14} className="text-emerald-500" /> : <TrendingDown size={14} className="text-rose-500" />}
                   <span className={`font-mono text-sm font-bold ${isPriceUp ? 'text-emerald-500' : 'text-rose-500'}`}>
                      ${currentPrice.toFixed(2)}
                   </span>
                </div>
             </div>
         </div>
         <div className="flex gap-2">
            <button className="px-4 py-1.5 bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-bold rounded-lg transition-colors shadow-lg shadow-emerald-500/20 active:scale-95 transform">
               Buy
            </button>
            <button className="px-4 py-1.5 bg-rose-500 hover:bg-rose-600 text-white text-xs font-bold rounded-lg transition-colors shadow-lg shadow-rose-500/20 active:scale-95 transform">
               Sell
            </button>
         </div>
      </div>

      {/* Main Chart */}
      <div className="flex-1 min-h-0">
        <ResponsiveContainer width="100%" height="100%">
          <ComposedChart 
            data={data} 
            margin={{ top: 20, right: 0, left: 0, bottom: 0 }}
            syncId="market-sync"
          >
            <CartesianGrid strokeDasharray="3 3" stroke={gridColor} vertical={false} opacity={0.4} />
            <XAxis 
              dataKey="time" 
              tickFormatter={formatDate} 
              stroke={axisColor} 
              tick={{ fontSize: 11, fill: axisTextColor }} 
              axisLine={false}
              tickLine={false}
              minTickGap={60}
              dy={10}
              hide={indicators.rsi || indicators.macd} // Hide X Axis if indicators are below
            />
            <YAxis 
              domain={['auto', 'auto']} 
              orientation="right" 
              stroke={axisColor} 
              tick={{ fontSize: 11, fill: axisTextColor, fontFamily: 'JetBrains Mono' }} 
              tickFormatter={(val) => val.toFixed(2)}
              axisLine={false}
              tickLine={false}
              dx={5}
            />
            <Tooltip content={<CustomTooltip />} cursor={{ stroke: axisColor, strokeWidth: 1, strokeDasharray: '4 4' }} />

            <Area 
              type="monotone" 
              dataKey="close" 
              data={historicalData}
              stroke={strokeColor} 
              fill={fillColor} 
              strokeWidth={2}
              isAnimationActive={false}
              connectNulls
            />

            {/* Moving Averages */}
            {indicators.ma && (
              <>
                <Line type="monotone" dataKey="ma7" stroke="#f97316" strokeWidth={1} dot={false} isAnimationActive={false} />
                <Line type="monotone" dataKey="ma25" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />
              </>
            )}

            {comparisons.map((compSymbol, idx) => (
              <Line
                key={compSymbol}
                type="monotone"
                dataKey={compSymbol}
                stroke={COMPARISON_COLORS[idx % COMPARISON_COLORS.length]}
                strokeWidth={2}
                dot={false}
                activeDot={{ r: 4, strokeWidth: 0 }}
                isAnimationActive={true}
                connectNulls
              />
            ))}

            <Line 
              type="monotone"
              dataKey="close"
              data={predictionDisplayData}
              stroke="#818cf8"
              strokeWidth={3}
              strokeDasharray="4 4"
              dot={{ r: 4, fill: "#818cf8", strokeWidth: 2, stroke: isDarkMode ? "#0B0E14" : "#ffffff" }}
              activeDot={{ r: 7, fill: "#a5b4fc", stroke: "#6366f1", strokeWidth: 2 }}
              isAnimationActive={true}
              animationDuration={1500}
              filter="url(#glow)"
            />

            {predictionData.length > 0 && (
               <Area
                  type="monotone"
                  dataKey="close"
                  data={predictionDisplayData}
                  stroke="none"
                  fill="url(#pattern-stripe)"
                  isAnimationActive={true}
                  animationDuration={1500}
               />
            )}

            {predictionData.length > 0 && lastHistorical && (
               <ReferenceLine x={lastHistorical.time} stroke="#6366f1" strokeDasharray="3 3" strokeOpacity={0.8} />
            )}
          </ComposedChart>
        </ResponsiveContainer>
      </div>

      {/* RSI Indicator Chart */}
      {indicators.rsi && (
        <div className="h-[100px] border-t border-border">
          <ResponsiveContainer width="100%" height="100%">
             <ComposedChart data={data} margin={{ top: 5, right: 0, left: 0, bottom: 0 }} syncId="market-sync">
                <CartesianGrid strokeDasharray="3 3" stroke={gridColor} vertical={false} opacity={0.3} />
                <XAxis dataKey="time" hide />
                <YAxis 
                   domain={[0, 100]} 
                   orientation="right" 
                   stroke={axisColor} 
                   tick={{ fontSize: 9, fill: axisTextColor }} 
                   axisLine={false}
                   tickLine={false}
                   ticks={[30, 70]}
                   width={40}
                />
                <Tooltip content={<CustomTooltip />} cursor={{ stroke: axisColor, strokeWidth: 1, strokeDasharray: '4 4' }} />
                <ReferenceLine y={70} stroke="#ef4444" strokeDasharray="3 3" opacity={0.5} />
                <ReferenceLine y={30} stroke="#10b981" strokeDasharray="3 3" opacity={0.5} />
                <Line type="monotone" dataKey="rsi" stroke="#a855f7" strokeWidth={1.5} dot={false} isAnimationActive={false} />
             </ComposedChart>
          </ResponsiveContainer>
        </div>
      )}

      {/* MACD Indicator Chart */}
      {indicators.macd && (
        <div className="h-[100px] border-t border-border">
          <ResponsiveContainer width="100%" height="100%">
             <ComposedChart data={data} margin={{ top: 5, right: 0, left: 0, bottom: 0 }} syncId="market-sync">
                <CartesianGrid strokeDasharray="3 3" stroke={gridColor} vertical={false} opacity={0.3} />
                {!indicators.rsi && (
                   <XAxis 
                     dataKey="time" 
                     tickFormatter={formatDate} 
                     stroke={axisColor} 
                     tick={{ fontSize: 11, fill: axisTextColor }} 
                     axisLine={false}
                     tickLine={false}
                     minTickGap={60}
                     dy={5}
                     height={20}
                   />
                )}
                {indicators.rsi && <XAxis dataKey="time" hide />}
                <YAxis 
                   orientation="right" 
                   stroke={axisColor} 
                   tick={{ fontSize: 9, fill: axisTextColor }} 
                   axisLine={false}
                   tickLine={false}
                   width={40}
                />
                <Tooltip content={<CustomTooltip />} cursor={{ stroke: axisColor, strokeWidth: 1, strokeDasharray: '4 4' }} />
                <ReferenceLine y={0} stroke={axisColor} strokeOpacity={0.2} />
                <Bar dataKey="macdHist" fill="#94a3b8">
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={(entry.macdHist || 0) > 0 ? '#10b981' : '#ef4444'} opacity={0.5} />
                  ))}
                </Bar>
                <Line type="monotone" dataKey="macd" stroke={isDarkMode ? "#fff" : "#334155"} strokeWidth={1} dot={false} isAnimationActive={false} />
                <Line type="monotone" dataKey="macdSignal" stroke="#f97316" strokeWidth={1} dot={false} isAnimationActive={false} />
             </ComposedChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
};

export default MarketChart;

import React from 'react';
import { LayoutDashboard, LineChart, PieChart, Settings, Layers, X, Moon, Sun } from 'lucide-react';
import { Stock, ViewType } from '../../types';

interface SidebarProps {
  watchlist: Stock[];
  currentStock: Stock;
  onSelectStock: (stock: Stock) => void;
  currentView: ViewType;
  onViewChange: (view: ViewType) => void;
  isOpen?: boolean;
  onClose?: () => void;
  isDarkMode: boolean;
  toggleTheme: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  watchlist, 
  currentStock, 
  onSelectStock,
  currentView,
  onViewChange,
