import { PREDICTION_COLOR, PREDICTION_STROKE_WIDTH } from '../../constants';

// ... other imports

interface MarketChartProps {
    data: any[];
    predictionData: any[];
    indicators: {
        ma: boolean;
    };
    onBuy: () => void;
    onSell: () => void;
    currentPrice: number;
}

const MarketChart: React.FC<MarketChartProps> = ({ data, predictionData, indicators, onBuy, onSell, currentPrice }) => {
    const [predictionDisplayData, setPredictionDisplayData] = useState<any[]>([]);

    useEffect(() => {
        // Set predictionDisplayData only if predictionData is available
        if (predictionData && predictionData.length > 0) {
            setPredictionDisplayData(predictionData);
        } else {
            setPredictionDisplayData([]);
        }
    }, [predictionData]);


    const renderCustomDot = (props: any) => {
        const { cx, cy, index } = props;
        return (
            <circle cx={cx} cy={cy} r={4} fill={PREDICTION_COLOR} stroke="white" strokeWidth={2} />
        );
    };

    const CustomTooltip = ({ active, payload, label }: { active: boolean; payload: any[]; label: any }) => {
        if (active && payload && payload.length) {
            const data = payload[0].payload;
            return (
                <div className="custom-tooltip">
                    <p className="label">{`Date: ${formatDate(label)}`}</p>
                    {payload.map((item, index) => (
                        <p key={index} className="value">
                            {`${item.name}: ${formatNumber(item.value)}`}
                        </p>
                    ))}
                    {data.aiPrediction && (
                        <p className="ai-prediction">
                            <ZapIcon className="zap-icon" /> AI Prediction: {formatNumber(data.aiPrediction)}
                        </p>
                    )}
                </div>
            );
        }
        return null;
    };


    return (
